      linkedinText: '\u05d4\u05ea\u05d7\u05d1\u05e8\u05d5 \u05d0\u05d9\u05ea\u05e0\u05d5 \u05d1\u05dc\u05d9\u05e0\u05e7\u05d3\u05d0\u05d9\u05df',
